local idx = 1
request = function()
  local u = updates[idx]
  idx = idx + 1
  if idx > #updates then idx = 1 end
  wrk.method = "PUT"
  wrk.headers["Content-Type"] = "application/json"
  wrk.body = u.body
  return wrk.format("PUT", "/api/v1/users/" .. u.id)
end
